4,"speaker_name":"Colin Costigan"},{"text":"Then we bring them into Premiere and then after Effects.","index":321,"end_time":1276.9,"speaker_id":1,"start_time":1274.38,"speaker_name":"Colin Costigan"},{"text":"Okay.","index":322,"end_time":1278.58,"speaker_id":2,"start_time":1278.02,"speaker_name":"Axel Völker"},{"text":"Okay.","index":323,"end_time":1279.86,"speaker_id":0,"start_time":1279.46,"speaker_name":"Axel Völker"},{"text":"Then we have to see how we give you the feedback and translations.","index":324,"end_time":1284.26,"speaker_id":0,"start_time":1279.86,"speaker_name":"Axel Völker"},{"text":"Yeah, we''ll be able to give you versions where you can leave feedback.","index":325,"end_time":1290.66,"speaker_id":1,"start_time":1285.78,"speaker_name":"Colin Costigan"},{"text":"There''s another tool that we use that''s not markup.","index":326,"end_time":1292.7,"speaker_id":1,"start_time":1290.66,"speaker_name":"Colin Costigan"},{"text":"It''s called Frame.","index":327,"end_time":1293.46,"speaker_id":1,"start_time":1292.7,"speaker_name":"Colin Costigan"},{"text":"That just plays the video.","index":328,"end_time":1294.74,"speaker_id":1,"start_time":1293.86,"speaker_name":"Colin Costigan"},{"text":"And you can leave a timestamp comment directly in there for translations, anything that we need.","index":329,"end_time":1299.35,"speaker_id":1,"start_time":1294.74,"speaker_name":"Colin Costigan"},{"text":"Okay.","index":330,"end_time":1303.35,"speaker_id":2,"start_time":1302.95,"speaker_name":"Axel Völker"},{"text":"And there''s going to be an AI generated voice.","index":331,"end_time":1306.79,"speaker_id":2,"start_time":1303.35,"speaker_name":"Axel Völker"},{"text":"Right.","index":332,"end_time":1307.19,"speaker_id":2,"start_time":1306.79,"speaker_name":"Axel Völker"},{"text":"And yeah, it''s really a bit hard to say how that video would look just from the screenshots.","index":333,"end_time":1313.79,"speaker_id":2,"start_time":1307.27,"speaker_name":"Axel Völker"},{"text":"So it''s a bit.","index":334,"end_time":1314.55,"speaker_id":2,"start_time":1313.79,"speaker_name":"Axel Völker"},{"text":"It would help when we.","index":335,"end_time":1317.75,"speaker_id":2,"start_time":1315.35,"speaker_name":"Axel Völker"},{"text":"I think.","index":336,"end_time":1318.39,"speaker_id":2,"start_time":1317.99,"speaker_name":"Axel Völker"},{"text":"I think we didn''t we review the English text already?","index":337,"end_time":1320.79,"speaker_id":2,"start_time":1318.39,"speaker_name":"Axel Völker"},{"text":"I mean, I can go through it again, but.","index":338,"end_time":1322.63,"speaker_id":2,"start_time":1320.87,"speaker_name":"Axel Völker"},{"text":"Yeah, yeah, we did.","index":339,"end_time":1324.36,"speaker_id":1,"start_time":1323.56,"speaker_name":"Colin Costigan"},{"text":"It will probably be easier to just.","index":340,"end_time":1328.76,"speaker_id":2,"start_time":1327.24,"speaker_name":"Axel Völker"},{"text":"See how the video looks to get a better idea.","index":341,"end_time":1330.84,"speaker_id":0,"start_time":1328.76,"speaker_name":"Axel Völker"},{"text":"All right, then, Natalie, we''ll move into getting the first cut developed.","index":342,"end_time":1335.08,"speaker_id":1,"start_time":1331,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":343,"end_time":1336.08,"speaker_id":0,"start_time":1335.64,"speaker_name":"Axel Völker"},{"text":"Where is that actually?","index":344,"end_time":1337,"speaker_id":2,"start_time":1336.08,"speaker_name":"Axel Völker"},{"text":"Is that.","index":345,"end_time":1337.64,"speaker_id":2,"start_time":1337.08,"speaker_name":"Axel Völker"},{"text":"That''s interesting.","index":346,"end_time":1340.56,"speaker_id":0,"start_time":1339.8,"speaker_name":"Axel Völker"},{"text":"Where''s the screenshots coming from?","index":347,"end_time":1342.12,"speaker_id":0,"start_time":1340.56,"speaker_name":"Axel Völker"},{"text":"Oh, that is the.","index":348,"end_time":1346.96,"speaker_id":2,"start_ti