  '[{"text":"Send RingCentral page design and copy for team review (02:09)","completed":false},{"text":"Build blog post category templates once Lindsey provides category list (04:03)","completed":false},{"text":"Finalize HubSpot forms integration, handling routing for multiple Gravity Forms (08:15)","completed":false},{"text":"Conduct thorough audit of price offer campaign and evaluate future direction (16:22)","completed":false},{"text":"Create written process for campaign evaluations with timelines for testing, changes, and kills (15:40)","completed":false},{"text":"Review and send recommendations for underperforming Google ad groups including 3Cx and Amazon Connect (13:50)","completed":false},{"text":"Implement enhanced internal linking and embed blog and assessment content directly into competitor landing pages like RingCentral (19:10)","completed":false},{"text":"Check Bing ads platform for RingCentral trademark blocking and provide update (26:49)","completed":false},{"text":"Provide list of blog categories to Colin for template building (04:03)","completed":false},{"text":"Send batch of form IDs needed for HubSpot implementation to Colin (07:59)","completed":false},{"text":"Conduct internal audits on customer journey flows on landing pages to ensure full query coverage and funnel paths (16:56)","completed":false},{"text":"Continue writing RingCentral and Comcast competitor blogs including assessments (20:14)","completed":false},{"text":"Prepare content revisions focused on AI intent for existing blogs and coordinate rewriting (24:51)","completed":false},{"text":"Provide batch lists of new form IDs for HubSpot integration to Colin (07:59)","completed":false}]'::jsonb,
